item.content:encoded:
.keynotebox {color:white;overflow:hidden; margin:auto; width:50%; text-align:center;margin-bottom:20px;}
.keynoteimg{width:140px;margin:auto;}

.keynotename, .careername, .coursename {font-weight:bolder;font-size:14px;}
.keynoteuni, .careeruni, .courseuni{font-size:11px;}

.careerbox {color:white;overflow:hidden; width:33%; text-align:center; float: left;height:140px;}
.careerimg{width:80px;margin:auto;}

.courseimg{width:80px;margin:auto;}
.coursetext{text-align:center;color:white; margin:auto;}
.courseexp{padding:20px;color:white;font-size:11px;}



span.featured-icon i, span.multi-featured-icon i{border:none; font-size:50px;}
.featured-section h3{text-transform:uppercase; font-size:20px;padding-bottom:20px;}


.header-wrapper {display:none}


ul.multiple-featured-section {padding-top:0px;}
ul.multiple-testimonial-section {padding-top:20px;}
.main-header-section{padding-top:100px;}


table.programme {border-spacing: 0px 0px;}

.text-footer a:hover{color:darkred;}

.testimonials-holder {
    padding: 0 !important;
}

