[{"id":"c0a7e95","elType":"section","settings":[],"elements":[{"id":"f0614d0","elType":"column","settings":{"_column_size":100,"_inline_size":null},"elements":[{"id":"296a870","elType":"widget","settings":{"html":"<style>
/* GENEL STİL SIFIRLAMASI VE FONT */
.workshop-container {
    max-width: 1000px;
    margin: 40px auto;
    font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
}

.workshop-card {
    border: 1px solid #333;
    border-radius: 8px;
    padding: 50px;
    margin-bottom: 40px; /* Workshoplar arasında boşluk */
    box-shadow: 0 8px 25px rgba(0, 0, 0, 0.1);
    background-color: #fcfcfc;
    color: #333;
}

/* TBA DUYURU KART STİLİ */
.workshop-card.tba-card {
    border: 2px dashed #CC0000; /* Kırmızı kesik çizgi vurgusu */
    background-color: #fff8f8; /* Çok açık kırmızı arka plan */
    text-align: center;
    padding: 60px 50px;
}

.tba-card .tba-text {
    color: #CC0000;
    font-size: 48px;
    font-weight: bold;
    margin-top: 10px;
    margin-bottom: 10px;
    letter-spacing: 3px;
}

.tba-card .tba-subtext {
    font-size: 18px;
    color: #555;
}

/* BAŞLIKLAR */
.workshop-card h1.main-title {
    color: #CC0000;
    font-size: 38px;
    text-align: center;
    margin-bottom: 10px;
    padding-bottom: 15px;
    letter-spacing: 1.5px;
    text-transform: uppercase;
}

.workshop-card h2,
.workshop-card h3 {
    color: #222;
    font-size: 24px;
    margin-top: 40px;
    margin-bottom: 20px;
    padding-left: 10px;
    border-left: 4px solid #CC0000;
}

/* SUMMARY BLOCK */
.workshop-summary {
    text-align: center;
    margin-bottom: 40px;
    padding: 20px 0;
    border-top: 2px solid #333;
    border-bottom: 2px solid #333;
}

.summary-item {
    display: inline-block;
    margin: 0 25px;
    font-size: 17px;
    line-height: 1.4;
}

.summary-item strong {
    color: #CC0000;
    display: block;
    font-size: 13px;
    text-transform: uppercase;
    letter-spacing: 1px;
    margin-bottom: 5px;
}

/* LIST STYLES */
.content-list {
    list-style: none;
    padding-left: 30px;
    margin-bottom: 25px;
}

.content-list li {
    padding-left: 18px;
    position: relative;
    margin-bottom: 12px;
    line-height: 1.6;
    color: #444;
}

.content-list li:before {
    content: "▪";
    color: #CC0000;
    font-weight: bold;
    display: inline-block;
    width: 1em;
    margin-left: -1em;
    position: absolute;
    left: 0;
    font-size: 1.1em;
    top: 0;
}

/* PARAGRAPH STYLING */
.workshop-card p {
    line-height: 1.7;
    margin-bottom: 20px;
    color: #555;
}

.workshop-card p strong {
    color: #222;
    font-size: 18px;
    display: block;
    margin-bottom: 10px;
    margin-top: 25px;
}


/* RESPONSIVENESS (Öncekiyle aynı, sadece kapsayıcıya uygulandı) */
@media (max-width: 1024px) {
    .workshop-container {
        max-width: 90%;
    }
}
@media (max-width: 768px) {
    .workshop-card {
        padding: 30px;
    }
    .workshop-card h1.main-title {
        font-size: 32px;
    }
    .summary-item {
        margin: 10px 15px;
        font-size: 16px;
        display: block;
    }
    .summary-item strong {
        display: inline;
    }
    .content-list {
        padding-left: 20px;
    }
    .tba-card .tba-text {
        font-size: 36px;
    }
}
@media (max-width: 480px) {
    .workshop-card {
        padding: 20px;
    }
    .workshop-card h1.main-title {
        font-size: 26px;
    }
    .tba-card .tba-text {
        font-size: 30px;
    }
}
</style>

<div class="workshop-container">

    <div class="workshop-card">
        <h1 class="main-title">WORKSHOP 1 | Fundamentals of Variant Filtering in the Genome</h1>

        <div class="workshop-summary">
            <div class="summary-item">
                <strong>Instructor</strong>
                Dr. Özkan Özdemir | Acıbadem University
            </div>
            <div class="summary-item">
                <strong>Quota</strong>
                25 - 30 People
            </div>
            <div class="summary-item">
                <strong>Date & Time</strong>
                October 30, 2025 | 13.30 - 15.00
            </div>
        </div>

        <h2>Pre-Workshop Expectations from Participants</h2>
        <p>Participation with a personal computer is expected.</p>

        <h2>Variant Interpretation Workshop Format</h2>
        <ul class="content-list">
            <li>Presentation</li>
            <li>Gennext Demo</li>
            <li>Hands-on training</li>
        </ul>

        <h2>PART 1: THEORETICAL PRESENTATION</h2>

        <p><strong>Basic Concepts & Terminology</strong></p>
        <ul class="content-list">
            <li>Variant types (SNV, InDel, CNV)</li>
            <li>Germline vs Somatic variants</li>
            <li>VCF format and NGS data</li>
        </ul>

        <p><strong>Variant Filtering Strategy</strong></p>
        <ul class="content-list">
            <li>Filtering pyramid</li>
            <li>Frequency, quality, and functional impact filters</li>
            <li>Mendelian disease and cancer approaches</li>
        </ul>

        <p><strong>Tools & Databases</strong></p>
        <ul class="content-list">
            <li>In-silico tools (CADD, SIFT, PolyPhen-2)</li>
            <li>ClinVar, gnomAD, OMIM</li>
            <li>ACMG/AMP classification criteria</li>
        </ul>

        <h2>PART 2: GENNEXT DEMO</h2>

        <p><strong>Germline Analysis</strong></p>
        <ul class="content-list">
            <li>Platform introduction</li>
            <li>Filtering and ACMG assessment</li>
        </ul>

        <p><strong>Learning Objectives</strong></p>
        <ul class="content-list">
            <li>Understanding the variant filtering logic</li>
            <li>Familiarity with the Gennext platform</li>
            <li>Applying ACMG criteria</li>
        </ul>
    </div>
    <div class="workshop-card tba-card">
        <h1 class="main-title">WORKSHOP 2 | Transcriptome Analysis</h1>

        <p class="tba-text">T.B.A.</p>

        <p class="tba-subtext">
            The content for Workshop 2 will be announced soon. 
            <br>Please follow our updates!
        </p>

        <div class="workshop-summary">
            <div class="summary-item">
                <strong>Instructor</strong>
                Selcen Arı Yuka
            </div>
            <div class="summary-item">
                <strong>Date & Time</strong>
                October 30, 2025 | 15.00 - 17.00
            </div>
        </div>
    </div>
    </div>"},"elements":[],"widgetType":"html"}],"isInner":false}],"isInner":false}]

